+/// Encode all metrics as Prometheus text format.
+pub fn encode_metrics() -> Result<String> {
+    let encoder = TextEncoder::new();
+    let mut buffer = Vec::new();
+    encoder.encode(&REGISTRY.gather(), &mut buffer)?;
+    Ok(String::from_utf8(buffer)?)
+}
